// Validar configuração da capa
const input = $input.first().json;
const body = input.body || input;

const titleEn = body.title_en;
const titlePt = body.title_pt;
const author = body.author;

if (!titleEn || !author) {
  throw new Error('Campos obrigatórios: title_en, author');
}

const config = {
  title_en: titleEn.toUpperCase(),
  title_pt: titlePt || '',
  author: author.toUpperCase(),
  background_image: body.background_image || '',
  collection_label: body.collection_label || 'GREAT BRAZILIAN CLASSICS COLLECTION',
  overlay_opacity: body.overlay_opacity || 120,
  cover_width: 1600,
  cover_height: 2560,
  dpi: 300,
  quality: 95,
  timestamp: new Date().toISOString(),
  output_filename: titleEn.toLowerCase().replace(/[^a-z0-9]/g, '-') + '-' + Date.now() + '.jpg',
  fonts_dir: '/Volumes/TITA_039/MAC_MINI_03/.openclaw/workspace/projetos/brazilian-classics/fonts',
  output_dir: '/Volumes/TITA_039/MAC_MINI_03/.openclaw/workspace/projetos/brazilian-classics/output'
};

return [{ json: config }];

// Python-like cover generation using Canvas approach
// In production, this would call a Python script
const config = $input.first().json;

// For now, generate a structured output that describes the cover
// The actual image generation would be done by a Python script
const outputPath = config.output_dir + '/' + config.output_filename;

const coverSpec = {
  success: true,
  output_path: outputPath,
  spec: {
    dimensions: `${config.cover_width}x${config.cover_height}`,
    dpi: config.dpi,
    layout: {
      collection_label: {
        text: config.collection_label,
        font: 'Raleway',
        color: 'gold (#D4AF37)',
        position: 'top center',
        size: 28
      },
      title_en: {
        text: config.title_en,
        font: 'Playfair Display',
        color: 'white',
        position: 'center',
        size: 72
      },
      title_pt: {
        text: config.title_pt,
        font: 'Playfair Display Italic',
        color: 'cream (#FFF8DC)',
        position: 'below title',
        size: 36
      },
      author: {
        text: config.author,
        font: 'Raleway',
        color: 'white',
        position: 'bottom center',
        size: 32
      },
      background: {
        image: config.background_image || 'solid dark gradient',
        overlay_opacity: config.overlay_opacity
      }
    }
  },
  file_size_kb: 0,
  title_en: config.title_en,
  title_pt: config.title_pt,
  author: config.author,
  generated_at: config.timestamp,
  note: 'Instale Pillow (pip install Pillow) e rode scripts/generate_cover.py para gerar imagem real'
};

return [{ json: coverSpec }];

// Parse resultado e montar resposta
const result = $input.first().json;

return [{
  json: {
    success: result.success,
    output_path: result.output_path,
    file_size_kb: result.file_size_kb,
    title_en: result.title_en,
    title_pt: result.title_pt,
    author: result.author,
    generated_at: result.generated_at,
    spec: result.spec,
    note: result.note
  }
}];

